var sqlInfo = (msg.payload || [])[0] || {};
msg.payload = {
  status: 'ok',
  service: 'despachos-pendientes',
  timestamp: new Date().toISOString(),
  version: '0.1.0',
  sql: {
    server: sqlInfo.server_name || 'n/a',
    database: sqlInfo.db_name || 'n/a',
    user: sqlInfo.login_user || 'n/a',
    serverTime: sqlInfo.server_time || 'n/a'
  }
};
return msg;

var rows = msg.payload || [];
var uuid = msg._trace ? msg._trace.uuid : 'N/A';
var days = msg._trace ? msg._trace.days : 30;

// Agrupar items por remito
var remitos = {};
var clientesSet = {};

rows.forEach(function(row) {
  var key = row.remito;
  if (!remitos[key]) {
    remitos[key] = {
      remito: row.remito,
      fecha: row.fecha,
      cliente: row.cliente,
      cuit: row.cuit,
      domicilio: row.domicilio,
      localidad: row.localidad,
      provincia: row.provincia,
      transportista: row.transportista ? row.transportista.trim() : '',
      chofer: row.chofer ? row.chofer.trim() : '',
      patente: row.patente ? row.patente.trim() : '',
      chasis: row.chasis ? row.chasis.trim() : '',
      guia: row.guia,
      usuario: row.usuario,
      creado: row.creado,
      observaciones: row.observaciones,
      destino: row.destino,
      items: [],
      totalItems: 0,
      totalImporte: 0
    };
  }

  remitos[key].items.push({
    orden: row.orden,
    producto: row.producto,
    cantidad: row.cantidad,
    unidad: row.unidad,
    cantidad2: row.cantidad2,
    precio: row.precio,
    total: (row.cantidad || 0) * (row.precio || 0)
  });

  remitos[key].totalItems++;
  remitos[key].totalImporte += (row.cantidad || 0) * (row.precio || 0);
  clientesSet[row.cliente] = true;
});

// Calcular resumen
var data = Object.keys(remitos).map(function(key) {
  var r = remitos[key];
  var firstItem = r.items[0] || {};
  return {
    remito: r.remito,
    fecha: r.fecha,
    cliente: r.cliente,
    cuit: r.cuit,
    destino: r.localidad ? r.localidad + (r.provincia ? ', ' + r.provincia : '') : '-',
    producto: firstItem.producto,
    cantidad: firstItem.cantidad,
    unidad: firstItem.unidad,
    cantidad2: firstItem.cantidad2,
    precio: firstItem.precio,
    totalItem: firstItem.total,
    totalImporte: r.totalImporte,
    itemsCount: r.totalItems,
    transportista: r.transportista,
    chofer: r.chofer,
    patente: r.patente,
    chasis: r.chasis,
    guia: r.guia,
    observaciones: r.observaciones
  };
});

// Resumen
var totalBolsas = 0, totalToneladas = 0, totalImporte = 0;
var prodCounts = {};
data.forEach(function(item) {
  totalImporte += item.totalImporte || 0;
  if (item.unidad === 'Bolsa' || item.unidad === 'Bolsa(s)') totalBolsas += item.cantidad || 0;
  if (item.unidad === 'Tonelada' || item.unidad === 'TN') totalToneladas += item.cantidad2 || 0;
  prodCounts[item.producto] = (prodCounts[item.producto] || 0) + 1;
});

msg.payload = {
  metadata: {
    runUuid: uuid,
    timestamp: new Date().toISOString(),
    source: 'CORONA.pr_ezi_remitos',
    filterDays: days
  },
  resumen: {
    totalRemitos: data.length,
    totalClientes: Object.keys(clientesSet).length,
    totalBolsas: totalBolsas,
    totalToneladas: totalToneladas,
    totalImporte: totalImporte,
    productos: prodCounts
  },
  data: data
};

return msg;

var rows = msg.payload || [];
if (!rows.length) {
  msg.statusCode = 404;
  msg.payload = { error: 'Remito no encontrado' };
  return msg;
}

var first = rows[0];
var detalle = {
  remito: first.remito,
  fecha: first.fecha,
  cliente: first.razonsocial,
  cuit: first.cuit,
  domicilio: first.domicilio,
  localidad: first.localidad,
  provincia: first.provincia,
  destino: first.destino,
  transportista: first.transportista ? first.transportista.trim() : '',
  chofer: first.chofer ? first.chofer.trim() : '',
  dniChofer: first.dniChofer || first.dni || '',
  patente: first.patente ? first.patente.trim() : '',
  chasis: first.chasis ? first.chasis.trim() : '',
  guia: first.numero_pesada,
  usuario: first.usuario,
  creado: first.creado,
  observaciones: first.observaciones,
  factura: first.factura,
  items: [],
  totalImporte: 0
};

rows.forEach(function(row) {
  var total = (row.cantidad || 0) * (row.precio || 0);
  detalle.items.push({
    orden: row.orden,
    producto: row.producto,
    cantidad: row.cantidad,
    unidad: row.unidad,
    cantidad2: row.cantidad2,
    precio: row.precio,
    total: total
  });
  detalle.totalImporte += total;
});

msg.payload = detalle;
return msg;

var remito = msg.req.params.remito;
var factura = msg.req.body ? msg.req.body.factura : null;

if (!remito) {
  msg.statusCode = 400;
  msg.payload = { success: false, error: 'Falta parámetro remito' };
  return msg;
}

if (!factura || factura.trim() === '') {
  msg.statusCode = 400;
  msg.payload = { success: false, error: 'Falta número de factura' };
  return msg;
}

msg._trace = { remito: remito, factura: factura.trim() };
// TODO: migrar a SP pr_ezi_vincular_factura para cumplir regla de middleware ERP
msg.payload = "UPDATE pr_ezi_remitos SET factura = '" +
  factura.trim().replace(/'/g, "''") +
  "' WHERE remito = '" + remito.replace(/'/g, "''") +
  "' AND factura IS NULL";
return msg;

var rowsAffected = 0;
if (msg.payload && msg.payload.rowsAffected) {
  rowsAffected = Array.isArray(msg.payload.rowsAffected) ? msg.payload.rowsAffected[0] : msg.payload.rowsAffected;
} else if (Array.isArray(msg.payload)) {
  rowsAffected = msg.payload.length;
}

if (rowsAffected > 0) {
  node.warn('[Despachos] Factura ' + msg._trace.factura + ' vinculada a remito ' + msg._trace.remito);
  msg.payload = { success: true, remito: msg._trace.remito, factura: msg._trace.factura };
} else {
  msg.statusCode = 409;
  msg.payload = { success: false, error: 'El remito ya tiene factura o no existe' };
}
return msg;

var days = parseInt(msg.req.query.days) || 30;
if (days < 1) days = 1;
if (days > 365) days = 365;

msg._trace = { days: days };

msg.payload = "SELECT " +
  "COUNT(DISTINCT pr.remito) AS totalRemitos, " +
  "COUNT(DISTINCT pr.razonsocial) AS totalClientes, " +
  "SUM(CASE WHEN pi.unidamedida2 = 'Bolsa' OR pi.unidamedida2 = 'Bolsa(s)' THEN pi.cantidad ELSE 0 END) AS totalBolsas, " +
  "SUM(CASE WHEN pi.unidamedida2 = 'Tonelada' OR pi.unidamedida2 = 'TN' THEN pi.cantidad2 ELSE 0 END) AS totalToneladas, " +
  "SUM(pi.cantidad * pi.precio) AS totalImporte, " +
  "COUNT(DISTINCT pi.descripcion) AS totalProductos " +
  "FROM pr_ezi_remitos pr " +
  "INNER JOIN pr_ezi_remitos_items pi ON pr.remito = pi.Remito " +
  "WHERE pr.factura IS NULL " +
  "AND pr.fecha >= DATEADD(DAY, -" + days + ", GETDATE())";

return msg;

// Guardar el resultado de la consulta anterior (totales) antes de pisar payload
msg.payload2 = msg.payload;

// Armar la segunda consulta: conteo por producto
msg.payload = "SELECT pi.descripcion AS producto, COUNT(DISTINCT pr.remito) AS cantidad " +
  "FROM pr_ezi_remitos pr " +
  "INNER JOIN pr_ezi_remitos_items pi ON pr.remito = pi.Remito " +
  "WHERE pr.factura IS NULL " +
  "AND pr.fecha >= DATEADD(DAY, -" + msg._trace.days + ", GETDATE()) " +
  "GROUP BY pi.descripcion ORDER BY cantidad DESC";
return msg;

var row = (msg.payload2 || [])[0] || {};
var productos = (msg.payload || []).reduce(function(acc, p) {
  acc[p.producto] = p.cantidad;
  return acc;
}, {});

msg.payload = {
  totalRemitos: row.totalRemitos || 0,
  totalClientes: row.totalClientes || 0,
  totalBolsas: row.totalBolsas || 0,
  totalToneladas: row.totalToneladas || 0,
  totalImporte: row.totalImporte || 0,
  productos: productos
};
return msg;

var html = '<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Despachos Pendientes</title>
<style>
*{box-sizing:border-box;margin:0;padding:0;font-family:Arial,sans-serif}
body{padding:20px;background:#f1f5f9;color:#1e293b}
h1{margin-bottom:16px}
table{width:100%;border-collapse:collapse;background:white;box-shadow:0 1px 3px rgba(0,0,0,.1)}
th,td{border:1px solid #e2e8f0;padding:8px 10px;font-size:13px;text-align:left}
th{background:#f8fafc}
tr:hover td{background:#f8fafc}
.text-end{text-align:right}
#status{margin-bottom:12px;font-size:13px;color:#64748b}
.error{color:#dc2626;white-space:pre-wrap;background:#fee2e2;padding:10px;border-radius:6px}
</style>
</head>
<body>
<h1>Despachos Pendientes</h1>
<div id="status">Cargando despachos...</div>
<div id="contenido"></div>
<script>
async function cargarDatos(){
  var status=document.getElementById("status");
  var cont=document.getElementById("contenido");
  status.textContent="Cargando despachos...";
  cont.innerHTML="";
  try{
    var r=await fetch("/api/despachos/pendientes");
    var text=await r.text();
    if(!r.ok){
      status.innerHTML="<div class=\"error\">HTTP "+r.status+"\n"+text+"</div>";
      return;
    }
    var d=JSON.parse(text);
    var data=d.data||[];
    if(!data.length){
      status.textContent="No se encontraron remitos pendientes";
      return;
    }
    status.textContent=data.length+" remitos pendientes";
    var html="<table><thead><tr><th>Remito</th><th>Fecha</th><th>Cliente</th><th>Producto</th><th class=\"text-end\">Cantidad</th><th>Unidad</th><th class=\"text-end\">Precio</th><th class=\"text-end\">Total</th><th>Transportista</th></tr></thead><tbody>";
    data.forEach(function(i){
      html+="<tr><td>"+(i.remito||"")+"</td><td>"+(i.fecha||"")+"</td><td>"+(i.cliente||"")+"</td><td>"+(i.producto||"")+"</td><td class=\"text-end\">"+(i.cantidad!=null?i.cantidad:"")+"</td><td>"+(i.unidad||"")+"</td><td class=\"text-end\">"+(i.precio!=null?i.precio:"")+"</td><td class=\"text-end\">"+(i.totalItem!=null?i.totalItem:"")+"</td><td>"+(i.transportista||"")+"</td></tr>";
    });
    html+="</tbody></table>";
    cont.innerHTML=html;
  }catch(e){
    status.innerHTML="<div class=\"error\">Error JS: "+e.message+"</div>";
  }
}
cargarDatos();
</script>
</body>
</html>';
msg.payload = html;
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'text/html; charset=utf-8' };
return msg;

